import json
from collections import defaultdict, deque

MARKOV_MODELS_DIR = 'models'

class MarkovChain:
    def __init__(self, order=1):
        self.order = order
        self.chain = defaultdict(deque)

    def train(self, text):
        words = text.split()
        for i in range(len(words) - self.order):
            context = tuple(words[i:i+self.order])
            next_word = words[i + self.order]
            self.chain[context].append(next_word)

    def generate(self, length=5, seed=None, random_seed=None):
        if not seed:
            seed = (random.random() * 1000) % len(self.chain)
        context = tuple([self._get_random_word(seed)] + [None] * (self.order - 1))
        generated_text = []
        for _ in range(length):
            next_word = self._next_word(context)
            if not next_word:
                break
            generated_text.append(next_word)
            seed = random.randint(0, 2**32) & 0xFFFFFFFF
            context = tuple([next_word] + [None] * (self.order - 1))
        return ' '.join(generated_text)

    def _get_random_word(self, seed):
        import random
        return random.choice(list(self.chain[seed]))

    def _next_word(self, context):
        if not self.chain.get(context):
            return None
        return random.choice(list(self.chain[context]))
